import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-student-form',
  templateUrl: './student-form.component.html',
})
export class StudentFormComponent implements OnInit {
  student: any = {
    name: '',
    email: '',
    phone: '',
    address: '',
    enrollmentDate: ''
  };

  isEditMode = false;
  studentId: number | null = null;

  constructor(private route: ActivatedRoute, private router: Router) {}

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    if (id) {
      this.isEditMode = true;
      this.studentId = +id;
      // TODO: load student data from your service
      // this.studentService.getById(this.studentId).subscribe(s => this.student = s);
    }
  }

  onSubmit(): void {
    if (this.isEditMode && this.studentId) {
      // TODO: this.studentService.update(this.studentId, this.student).subscribe(...)
      console.log('Updating student:', this.student);
    } else {
      // TODO: this.studentService.create(this.student).subscribe(...)
      console.log('Creating student:', this.student);
    }
    this.router.navigate(['/students']);
  }

  onCancel(): void {
    this.router.navigate(['/students']);
  }
}
